func:
let active = flow.get("simulation_active") ?? false;
let hour = flow.get("simulation_hour") ?? -1;
let speed = flow.get("simulation_speed") ?? 1000;

if (active === true){
    hour = (hour + 1) % 24;
    flow.set("simulation_hour", hour);
    msg.payload = hour;
    msg.delay = speed
    return msg;
} else {
    return null;
}

const hour = msg.payload;
const schedule = {
    0: [
        {topic: "greenhouse/yellowlight", payload: "100"},
        {topic: "greenhouse/purplelight", payload: "80"},
        {topic: "greenhouse/ventilation", payload: "true"}

    ],
    6: [
        {topic: "greenhouse/leftlamp", payload: "true"},
        {topic: "greenhouse/yellowlight", payload: "0"},
        {topic: "greenhouse/purplelight", payload: "0"}
    ],
    10: [
        {topic: "greenhouse/middlelamp", payload: "true"}
    ],
    12: [
        {topic: "greenhouse/rightlamp", payload: "true"},
        {topic: "greenhouse/frontwindow", payload: "true"},
        {topic: "greenhouse/backwindow", payload: "true"}
    ],
    14: [
        {topic: "greenhouse/leftlamp", payload: "false"}
    ],
    16: [
        {topic: "greenhouse/middlelamp", payload: "false"}
    ],
    17: [
        {topic: "greenhouse/frontwindow", payload: "false"},
        {topic: "greenhouse/backwindow", payload: "false"}
    ],
    20: [
        {topic: "greenhouse/rightlamp", payload: "false"},
        {topic: "greenhouse/yellowlight", payload: "100"},
        {topic: "greenhouse/purplelight", payload: "80"}
    ]
};

if (schedule[hour]) {
    schedule[hour].forEach(item => {
        node.send({topic: item.topic, payload: item.payload});
    });
}

return null;

flow.set("simulation_hour", -1)

const reset = [
    {topic: "greenhouse/leftlamp", payload: "false"},
    {topic: "greenhouse/middlelamp", payload: "false"},
    {topic: "greenhouse/rightlamp", payload: "false"},
    {topic: "greenhouse/yellowlight", payload: "0"},
    {topic: "greenhouse/purplelight", payload: "0"},
    {topic: "greenhouse/frontwindow", payload: "false"},
    {topic: "greenhouse/backwindow", payload: "false"},
    {topic: "greenhouse/ventilation", payload: "false"}
]

reset.forEach(item => {
        node.send({topic: item.topic, payload: item.payload});
    });
return null;

if (msg.payload.hőmérséklet !== undefined) flow.set("current_temperature", msg.payload.hőmérséklet);
if (msg.payload.páratartalom !== undefined) flow.set("current_humidity", msg.payload.páratartalom);
if (msg.payload.fényerő_jobb !== undefined) flow.set("current_lux", msg.payload.fényerő_jobb);
if (msg.payload.co2_ppm !== undefined) flow.set("current_co2", msg.payload.co2_ppm);
if (msg.payload.tvoc_ppb !== undefined) flow.set("current_tvoc", msg.payload.tvoc_ppb);
if (msg.payload.talaj_nedvesség_százalék !== undefined) flow.set("current_moisture", msg.payload.talaj_nedvesség_százalék);

if (!(flow.get("automation_active") ?? false)) return null;

let hour = new Date().getHours();
let minutes = new Date().getMinutes();
let temperature = flow.get("current_temperature") || 22;
let humidity = flow.get("current_humidity") || 30;
let lux = flow.get("current_lux") || 2000;
let co2 = flow.get("current_co2") || 400;
let tvoc = flow.get("current_tvoc") || 0;
let moisture = flow.get("current_moisture") || 89;

let temperature_minimum = flow.get("temperature_minimum") || 18;
let temperature_maximum = flow.get("temperature_maximum") || 25;
let humidity_maximum = flow.get("humidity_maximum") || 70;
let lux_minimum = flow.get("lux_minimum") || 1000;
let lux_maximum = flow.get("lux_maximum") || 10000;
let daylight_start = flow.get("daylight_start") || 7;
let daylight_end = flow.get("daylight_end") || 21;
let moisture_threshold = flow.get("moisture_threshold") || 55;

let ventilation_needed = flow.get("ventilation_active") || false;
let window_open = flow.get("window_active") || false;
let heating_on = flow.get("heating_active") || false;
let led_lights_on = flow.get("led_lights_active") || false;
let pump_on = false;

let is_daylight = (hour >= daylight_start && hour < daylight_end);
let air_circulation = (minutes < 10);
let morning_ventilation = (hour === daylight_start && minutes < 5);
let night_ventilation = (hour === daylight_end && minutes < 5);
let moisture_check = (hour === daylight_start && minutes === 10);
let watered_today = flow.get("watered_today") || false;

let effective_minimum_temperature = is_daylight ? temperature_minimum : (temperature_minimum - 4);

if (temperature > temperature_maximum || humidity > humidity_maximum || co2 > 1000 || tvoc > 300 || air_circulation) {
    ventilation_needed = true;
}
else if (temperature < (temperature_maximum - 2) && humidity < (humidity_maximum - 5) && co2 < 800 && tvoc < 150 && !air_circulation) {
    ventilation_needed = false;
}

if (temperature > temperature_maximum || humidity > humidity_maximum || co2 > 1000 || tvoc > 300 || morning_ventilation || night_ventilation) {
    window_open = true;
}
else if (temperature < (temperature_maximum - 2) && humidity < (humidity_maximum - 5) && co2 < 800 && tvoc < 150 && !morning_ventilation && !night_ventilation) {
    window_open = false;
}

if (temperature < effective_minimum_temperature) {
    heating_on = true;
}
else if (temperature > (effective_minimum_temperature + 2)) {
    heating_on = false;
}

if (is_daylight) {
    if (lux < lux_minimum) {
        led_lights_on = true;
    } else if (lux > lux_maximum) {
        led_lights_on = false;
    }
} else {
    led_lights_on = false;
}

if (moisture_check && moisture < moisture_threshold && !watered_today) {
    pump_on = true;
    flow.set("watered_today", true);
}

if (hour === daylight_end && minutes === 0) {
    flow.set("watered_today", false);
}

flow.set("ventilation_active", ventilation_needed);
flow.set("window_active", window_open);
flow.set("heating_active", heating_on);
flow.set("led_lights_active", led_lights_on);

node.send([
    { topic: "greenhouse/ventilation", payload: ventilation_needed ? "true" : "false" },
    { topic: "greenhouse/frontwindow", payload: window_open ? "true" : "false" },
    { topic: "greenhouse/backwindow", payload: window_open ? "true" : "false" },
    { topic: "greenhouse/leftlamp",    payload: heating_on ? "true" : "false" },
    { topic: "greenhouse/middlelamp",  payload: heating_on ? "true" : "false" },
    { topic: "greenhouse/rightlamp",   payload: heating_on ? "true" : "false" },
    { topic: "greenhouse/yellowlight", payload: led_lights_on ? "100" : "0" },
    { topic: "greenhouse/purplelight", payload: led_lights_on ? "80" : "0" },
    { topic: "greenhouse/pump", payload: pump_on ? "true" : "false" }
]);

return null;

if (msg.payload === false){
    msg.reset = true
    return msg;
}
